<template>
  <div class="category-menu-section">
    <b-container>
      <b-row>
        <b-col md="8">
          <a-card style="width: 100%;border-radius: 20px" class="mt-4 p-0">
            <h5 class="font-weight-bold">Shopping Cart ({{ cartProductCount }})</h5>
            <div class="row mt-4">
              <div class="col-6">
                <a-checkbox>
                  Select All
                </a-checkbox>
              </div>
              <div class="col-6 text-right">
                <a href="#" class="text-secondary"><i class="far fa-trash-alt"></i> DELETE</a>
              </div>
            </div>
          </a-card>
          <a-card style="width: 100%;border-radius: 20px" class="mt-4 p-0">
            <table v-for="(cart, i) in cartProductList" :key="i" class="mt-4">
              <tr>
                <td style="width: 5%">
                  <b-form-checkbox
                      id="checkbox-2"
                      name="checkbox-2"
                      value="accepted"
                      unchecked-value="not_accepted"
                  >
                  </b-form-checkbox>
                </td>
                <td style="width: 15%">
                  <router-link :to="'/product/'+cart.slug" target="_blank">
                    <b-img :src="showImage(loadProductDetails(cart.slug, 'main_image'))" fluid
                           alt="Responsive image" class="border"
                           style="max-width: 80px"></b-img>
                  </router-link>
                </td>
                <td style="width: 80%" class="p-2 break">
                  <router-link :to="'/product/'+cart.slug" target="_blank" style="color: #2f2c2c">
                    <h6 class="mb-0" style="font-size: 15px">{{ loadProductDetails(cart.slug, 'name') }}</h6>
                    <p class="mb-0 text-muted" style="font-size: 12px" v-if="cart.variation === 1">
                          <span v-for="(variation, k) in cart.variation_value" :key="k" class="mr-2">
                            <span class="font-weight-bold text-capitalize">{{ k }}: </span>{{ variation }}
                          </span>
                    </p>
                  </router-link>
                  <div class="product-price"></div>
                  <p class="mb-0 font-weight-bold" style="font-size: 12px;color: #00aced">
                    Free Shipping</p>
                </td>
                <td style="width: 20%" class="break">
                  <a href="delete" class="float-right mr-2" @click.prevent="deleteCartProduct(cart)"
                     style="color: rgb(40 167 69);font-size: 20px">
                    <i class="far fa-trash-alt"></i>
                  </a>
                  <a href="#" class="float-right mr-3"
                     style="color: rgb(40 167 69);font-size: 20px">
                    <i class="far fa-heart"></i>
                  </a>
                  <div class="clearfix"></div>
                  <div class="product-details-quantity mt-3">
                    <Quantity v-model="cart.qty" :min="minQty(cart)" :max="maxQty(cart)"/>
                  </div>
                </td>
              </tr>
            </table>
          </a-card>
        </b-col>
        <b-col md="4">
          <a-card style="width: 100%;border-radius: 20px" class="mt-4 p-0">
            <h5 class="font-weight-bold">Order Summary</h5>
            <div class="row">
              <div class="col-6 my-3">
                Subtotal
              </div>
              <div class="col-6 text-right my-3">
                US $0.00
              </div>
              <div class="col-6">
                Shipping
              </div>
              <div class="col-6 text-right">
                US $0.00
              </div>
            </div>
            <hr>
            <div class="row">
              <div class="col-6 mb-3">
                <h5 class="font-weight-bold">Total</h5>
              </div>
              <div class="col-6 text-right">
                <h5 class="font-weight-bold">US $0.00</h5>
              </div>
            </div>
            <a-button class="text-white bg-success w-100" style="border-color:rgb(54 132 72)"> PROCEED TO CHECKOUT
            </a-button>
          </a-card>
        </b-col>
      </b-row>
    </b-container>
  </div>
</template>

<script>
import {mapGetters} from "vuex";
import Quantity from "@/components/helper/Quantity";

export default {
  name: "Cart",
  components: {Quantity},
  methods: {
    loadProductDetails(slug, dataType) {
      let product = this.getProductBySlug(slug);
      if (product) return product[dataType];
    },
    deleteCartProduct(cart) {
      this.$store.commit('CART_REMOVE_SINGLE', cart);
      this.$store.commit('STORE_CART_PRODUCT', cart);
    },
    minQty(cart) {
      let product = this.getProductBySlug(cart.slug);
      if (product) {
        if (product.quantity.qty_manage === 1) return product.quantity.min_qty;
        else return 1;
      }
    },
    maxQty(cart) {
      let product = this.getProductBySlug(cart.slug);
      if (product) {
        let qty = 999999;
        if (product.quantity.stock === 2) {
          if (cart.variation === 1) {
            let e = product.price.stock;
            let result = e.find(value => value.sku === cart.variation_sku);
            qty = result.qty;
          } else qty = product.quantity.total;
          if (product.quantity.qty_manage === 1) return product.quantity.max_qty > qty ? qty : product.quantity.max_qty;
          else return qty;
        } else {
          if (product.quantity.qty_manage === 1) return product.quantity.max_qty;
          else return qty;
        }
      }
    }
  },
  computed: {
    ...mapGetters(["cartProductCount", "cartProductList", "getProductBySlug"]),
  }
}
</script>

<style scoped>
@media (max-width: 480px) {
  .break {
    display: table-row;
  }
}
</style>
